/// Circuit state for one processing channel.
///
/// Contains both per-sample state (v_prev, i_nl_prev) and sample-rate-dependent
/// matrices (s, a_neg, k, s_ni). Call [`set_sample_rate`](CircuitState::set_sample_rate)
/// before processing if the host sample rate differs from [`SAMPLE_RATE`].
#[derive(Clone, Debug)]
pub struct CircuitState {
    /// Previous node voltages v[n-1]
    pub v_prev: [f64; N],

    /// Previous nonlinear currents i_nl[n-1]
    pub i_nl_prev: [f64; M],

    /// Nonlinear currents from two samples ago i_nl[n-2] (for NR predictor)
    pub i_nl_prev_prev: [f64; M],

    /// DC operating point (for reset/sleep/wake)
    pub dc_operating_point: [f64; N],

    /// Previous input sample for trapezoidal integration
    pub input_prev: f64,

    /// Iteration count from last solve (for diagnostics)
    pub last_nr_iterations: u32,

    /// Diagnostic: peak absolute output (pre-clamp)
    pub diag_peak_output: f64,
    /// Diagnostic: number of times output exceeded ±10V
    pub diag_clamp_count: u64,
    /// Diagnostic: number of times NR hit max iterations
    pub diag_nr_max_iter_count: u64,
    /// Diagnostic: number of times NaN triggered state reset
    pub diag_nan_reset_count: u64,
    /// Diagnostic: number of times matrix inversion detected a singular matrix
    pub diag_singular_matrix_count: u64,

    /// S = A^{-1} matrix, recomputed by set_sample_rate
    pub s: [[f64; N]; N],

    /// A_neg = alpha*C - G matrix, recomputed by set_sample_rate
    pub a_neg: [[f64; N]; N],

    /// K = N_v * S * N_i kernel matrix, recomputed by set_sample_rate
    pub k: [[f64; M]; M],

    /// S * N_i product, recomputed by set_sample_rate
    pub s_ni: [[f64; M]; N],

    /// Potentiometer 0 current resistance (ohms)
    pub pot_0_resistance: f64,
    /// Potentiometer 0 previous timestep resistance (for trapezoidal A_neg correction)
    pub pot_0_resistance_prev: f64,

    /// Sherman-Morrison precomputed SU vector for pot 0 (recomputed by set_sample_rate)
    pub pot_0_su: [f64; N],
    /// Sherman-Morrison USU scalar for pot 0 (recomputed by set_sample_rate)
    pub pot_0_usu: f64,
    /// Sherman-Morrison NV_SU vector for pot 0 (recomputed by set_sample_rate)
    pub pot_0_nv_su: [f64; M],
    /// Sherman-Morrison U_NI vector for pot 0 (recomputed by set_sample_rate)
    pub pot_0_u_ni: [f64; M],

    // --- Runtime-adjustable device parameters ---
    // These fields are initialized from the corresponding DEVICE_N_* constants.
    // Modify them at runtime to change device behavior (e.g. tube aging, transistor matching).
    /// Device 0 IS (Diode) — runtime adjustable
    pub device_0_is: f64,

    /// Device 0 N_VT (Diode) — runtime adjustable
    pub device_0_n_vt: f64,

    /// Device 1 IS (Bjt) — runtime adjustable
    pub device_1_is: f64,

    /// Device 1 VT (Bjt) — runtime adjustable
    pub device_1_vt: f64,

    /// Device 1 BETA_F (Bjt) — runtime adjustable
    pub device_1_bf: f64,

    /// Device 1 BETA_R (Bjt) — runtime adjustable
    pub device_1_br: f64,

    /// Device 2 IS (Bjt) — runtime adjustable
    pub device_2_is: f64,

    /// Device 2 VT (Bjt) — runtime adjustable
    pub device_2_vt: f64,

    /// Device 2 BETA_F (Bjt) — runtime adjustable
    pub device_2_bf: f64,

    /// Device 2 BETA_R (Bjt) — runtime adjustable
    pub device_2_br: f64,
}

