impl CircuitState {
    /// Reset to DC operating point
    pub fn reset(&mut self) {
        self.v_prev = self.dc_operating_point;
        self.i_nl_prev = DC_NL_I;
        self.i_nl_prev_prev = DC_NL_I;
        self.input_prev = 0.0;
        self.last_nr_iterations = 0;
        self.diag_peak_output = 0.0;
        self.diag_clamp_count = 0;
        self.diag_nr_max_iter_count = 0;
        self.diag_nan_reset_count = 0;
        self.diag_singular_matrix_count = 0;

        self.pot_0_resistance = 9.99999999999999854e4;
        self.pot_0_resistance_prev = 9.99999999999999854e4;

        self.device_0_is = DEVICE_0_IS;

        self.device_0_n_vt = DEVICE_0_N_VT;

        self.device_1_is = DEVICE_1_IS;

        self.device_1_vt = DEVICE_1_VT;

        self.device_1_bf = DEVICE_1_BETA_F;

        self.device_1_br = DEVICE_1_BETA_R;

        self.device_2_is = DEVICE_2_IS;

        self.device_2_vt = DEVICE_2_VT;

        self.device_2_bf = DEVICE_2_BETA_F;

        self.device_2_br = DEVICE_2_BETA_R;
    }

    /// Set DC operating point (call after DC analysis)
    pub fn set_dc_operating_point(&mut self, v_dc: [f64; N]) {
        self.dc_operating_point = v_dc;
        self.v_prev = v_dc;
    }

    /// Recompute all sample-rate-dependent matrices for a new sample rate.
    ///
    /// Call this once during plugin initialization (NOT on the audio thread).
    /// This recomputes S, A_neg, K, S*N_i, inductor g_eq, and pot SM vectors
    /// from the stored G and C matrices.
    ///
    /// If `sample_rate` matches [`SAMPLE_RATE`], this is a no-op (the defaults
    /// are already correct).
    pub fn set_sample_rate(&mut self, sample_rate: f64) {
        if !(sample_rate > 0.0 && sample_rate.is_finite()) {
            return; // Invalid sample rate, keep defaults
        }

        // If same as codegen sample rate, reset to defaults (avoids numerical drift)
        if (sample_rate - SAMPLE_RATE).abs() < 0.5 {
            self.s = S_DEFAULT;
            self.a_neg = A_NEG_DEFAULT;
            self.k = K_DEFAULT;
            self.s_ni = S_NI_DEFAULT;

            self.pot_0_su = POT_0_SU;
            self.pot_0_usu = POT_0_USU;
            self.pot_0_nv_su = POT_0_NV_SU;
            self.pot_0_u_ni = POT_0_U_NI;

            return;
        }

        let internal_rate = sample_rate * OVERSAMPLING_FACTOR as f64;
        let alpha = 2.0 * internal_rate;

        // Build A = G + alpha*C
        let mut a = [[0.0f64; N]; N];
        for i in 0..N {
            for j in 0..N {
                a[i][j] = G[i][j] + alpha * C[i][j];
            }
        }

        // Build A_neg = alpha*C - G
        let mut a_neg = [[0.0f64; N]; N];
        for i in 0..N {
            for j in 0..N {
                a_neg[i][j] = alpha * C[i][j] - G[i][j];
            }
        }

        // Invert A to get S
        let (s, singular) = invert_n(a);
        if singular {
            self.diag_singular_matrix_count += 1;
        }

        // Compute S * N_i product (N x M)
        let mut s_ni = [[0.0f64; M]; N];
        for i in 0..N {
            for j in 0..M {
                let mut sum = 0.0;
                for kk in 0..N {
                    sum += s[i][kk] * N_I[j][kk]; // N_I is transposed: [M][N]
                }
                s_ni[i][j] = sum;
            }
        }

        // Compute K = N_v * S_NI (M x M)
        let mut k = [[0.0f64; M]; M];
        for i in 0..M {
            for j in 0..M {
                let mut sum = 0.0;
                for n_idx in 0..N {
                    sum += N_V[i][n_idx] * s_ni[n_idx][j];
                }
                k[i][j] = sum;
            }
        }

        self.s = s;
        self.a_neg = a_neg;
        self.k = k;
        self.s_ni = s_ni;

        // Recompute Sherman-Morrison vectors for pots
        {
            let mut u = [0.0f64; N];
            if POT_0_NODE_P > 0 {
                u[POT_0_NODE_P - 1] = 1.0;
            }
            if POT_0_NODE_Q > 0 {
                u[POT_0_NODE_Q - 1] = -1.0;
            }

            let mut su = [0.0f64; N];
            for i in 0..N {
                let mut sum = 0.0;
                for j in 0..N {
                    sum += self.s[i][j] * u[j];
                }
                su[i] = sum;
            }

            let mut usu = 0.0f64;
            for i in 0..N {
                usu += u[i] * su[i];
            }

            let mut nv_su = [0.0f64; M];
            for i in 0..M {
                let mut sum = 0.0;
                for j in 0..N {
                    sum += N_V[i][j] * su[j];
                }
                nv_su[i] = sum;
            }

            let mut u_ni = [0.0f64; M];
            for j in 0..M {
                let mut sum = 0.0;
                for i in 0..N {
                    sum += su[i] * N_I[j][i];
                }
                u_ni[j] = sum;
            }

            self.pot_0_su = su;
            self.pot_0_usu = usu;
            self.pot_0_nv_su = nv_su;
            self.pot_0_u_ni = u_ni;
        }
    }
}

/// Invert an N x N matrix using Gaussian elimination with partial pivoting.
///
/// Returns `(result, singular)` where `singular` is `true` if the matrix was
/// detected as singular (pivot below threshold). On singularity, the identity
/// matrix is returned as a safe fallback; the caller should record the event
/// via `diag_singular_matrix_count`.
fn invert_n(a: [[f64; N]; N]) -> ([[f64; N]; N], bool) {
    let mut aug = [[0.0f64; 2 * N]; N];
    for i in 0..N {
        for j in 0..N {
            aug[i][j] = a[i][j];
        }
        aug[i][N + i] = 1.0;
    }

    for col in 0..N {
        let mut max_row = col;
        let mut max_val = aug[col][col].abs();
        for row in (col + 1)..N {
            if aug[row][col].abs() > max_val {
                max_val = aug[row][col].abs();
                max_row = row;
            }
        }

        if max_val < 1e-30 {
            let mut result = [[0.0f64; N]; N];
            for i in 0..N {
                result[i][i] = 1.0;
            }
            return (result, true);
        }

        if max_row != col {
            aug.swap(col, max_row);
        }

        let pivot = aug[col][col];
        for row in (col + 1)..N {
            let factor = aug[row][col] / pivot;
            for j in col..(2 * N) {
                aug[row][j] -= factor * aug[col][j];
            }
        }
    }

    for col in (0..N).rev() {
        let pivot = aug[col][col];
        if pivot.abs() < 1e-30 {
            let mut result = [[0.0f64; N]; N];
            for i in 0..N {
                result[i][i] = 1.0;
            }
            return (result, true);
        }
        for j in 0..(2 * N) {
            aug[col][j] /= pivot;
        }
        for row in 0..col {
            let factor = aug[row][col];
            for j in 0..(2 * N) {
                aug[row][j] -= factor * aug[col][j];
            }
        }
    }

    let mut result = [[0.0f64; N]; N];
    for i in 0..N {
        for j in 0..N {
            result[i][j] = aug[i][N + j];
        }
    }
    (result, false)
}

